const items = $input.all();
const raw2026 = items[0]?.json || {};
const raw2022 = items[1]?.json || {};
const raw2018 = items[2]?.json || {};
const rawFDMatches = items[3]?.json || {};
const rawFDStandings = items[4]?.json || {};

// ===== HELPERS FD =====
function nameMatch(a, b) {
  if (!a || !b) return false;
  const n = s => s.toLowerCase().replace(/[^a-z]/g, '');
  const na = n(a), nb = n(b);
  return na === nb || na.includes(nb) || nb.includes(na);
}

function getTeamForm(teamName, limit=5) {
  const matches = (rawFDMatches.matches || [])
    .filter(m => nameMatch(m.homeTeam?.name, teamName) || nameMatch(m.homeTeam?.shortName, teamName) ||
                 nameMatch(m.awayTeam?.name, teamName) || nameMatch(m.awayTeam?.shortName, teamName))
    .filter(m => m.score?.fullTime?.home !== null && m.score?.fullTime?.home !== undefined)
    .sort((a, b) => new Date(b.utcDate) - new Date(a.utcDate))
    .slice(0, limit);
  return matches.map(m => {
    const isHome = nameMatch(m.homeTeam?.name, teamName) || nameMatch(m.homeTeam?.shortName, teamName);
    const s = m.score.fullTime;
    const tf = isHome ? s.home : s.away;
    const og = isHome ? s.away : s.home;
    const opp = isHome ? (m.awayTeam?.shortName || m.awayTeam?.name) : (m.homeTeam?.shortName || m.homeTeam?.name);
    const res = tf > og ? 'V' : tf === og ? 'E' : 'D';
    return { fecha: m.utcDate?.split('T')[0], rival: opp, resultado: res, marcador: `${tf}-${og}` };
  });
}

function getTeamStanding(teamName) {
  for (const group of (rawFDStandings.standings || [])) {
    for (const row of (group.table || [])) {
      if (nameMatch(row.team?.name, teamName) || nameMatch(row.team?.shortName, teamName)) {
        return {
          grupo: (group.group || '').replace('GROUP_', 'Grupo ') || group.stage,
          posicion: row.position, puntos: row.points,
          jugados: row.playedGames, victorias: row.won,
          empates: row.draw, derrotas: row.lost,
          gf: row.goalsFor, gc: row.goalsAgainst
        };
      }
    }
  }
  return null;
}

// ===== ELO =====
function calcElo(r18, r22, r26) {
  const ratings = {};
  function getElo(team) { if (!ratings[team]) ratings[team] = 1500; return ratings[team]; }
  function processRounds(rounds, baseK) {
    const allMatches = [];
    for (const round of (rounds || [])) {
      for (const m of (round.matches || [])) {
        if (m.score?.ft && m.date) allMatches.push({ ...m, roundName: round.name });
      }
    }
    allMatches.sort((a, b) => new Date(a.date) - new Date(b.date));
    for (const m of allMatches) {
      const t1 = m.team1?.name, t2 = m.team2?.name;
      if (!t1 || !t2) continue;
      const r1 = getElo(t1), r2 = getElo(t2);
      const [g1, g2] = m.score.ft;
      const e1 = 1 / (1 + Math.pow(10, (r2 - r1) / 400));
      const s1 = g1 > g2 ? 1 : g1 === g2 ? 0.5 : 0;
      const gd = Math.abs(g1 - g2);
      const gdMult = gd <= 1 ? 1 : gd === 2 ? 1.5 : Math.min(1.75 + (gd - 3) * 0.25, 2.5);
      const rn = (m.roundName || '').toLowerCase();
      const isKO = rn.includes('round of') || rn.includes('quarter') || rn.includes('semi') || rn.includes('final');
      const k = isKO ? baseK * 1.5 : baseK;
      ratings[t1] = Math.round(r1 + k * gdMult * (s1 - e1));
      ratings[t2] = Math.round(r2 + k * gdMult * ((1 - s1) - (1 - e1)));
    }
  }
  processRounds(r18, 30);
  processRounds(r22, 32);
  processRounds(r26, 40);
  return ratings;
}

// ===== xG ESTIMADO =====
function estimateXG(form, stats) {
  const avg22 = parseFloat(stats.wc2022?.avgGF || 0);
  const avg18 = parseFloat(stats.wc2018?.avgGF || 0);
  const histAvg = avg22 > 0 && avg18 > 0 ? avg22 * 0.6 + avg18 * 0.4
                : avg22 > 0 ? avg22 : avg18 > 0 ? avg18 : 1.0;
  if (!form || form.length === 0) return +histAvg.toFixed(2);
  const formGF = form.reduce((s, m) => s + parseInt((m.marcador||'0-0').split('-')[0] || 0), 0) / form.length;
  return +(formGF * 0.6 + histAvg * 0.4).toFixed(2);
}

// ===== LOCAL/VISITANTE =====
const HOSTS = {
  'United States': { label: '🏠 Local (sede principal)', boost: 0.15 },
  'USA': { label: '🏠 Local (sede principal)', boost: 0.15 },
  'Mexico': { label: '🏠 Co-sede', boost: 0.08 },
  'Canada': { label: '🏠 Co-sede', boost: 0.08 }
};
function getHomeFactor(teamName) {
  for (const [host, data] of Object.entries(HOSTS)) {
    if (nameMatch(teamName, host)) return data;
  }
  return { label: '✈️ Visitante', boost: 0 };
}

// ===== SUSPENSIONES POR TARJETAS =====
function getSuspensionRisk(teamName) {
  const yellows = {};
  for (const m of (rawFDMatches.matches || [])) {
    const isTeam = nameMatch(m.homeTeam?.name, teamName) || nameMatch(m.homeTeam?.shortName, teamName) ||
                   nameMatch(m.awayTeam?.name, teamName) || nameMatch(m.awayTeam?.shortName, teamName);
    if (!isTeam) continue;
    for (const b of (m.bookings || [])) {
      const isOurs = nameMatch(b.team?.name, teamName) || nameMatch(b.team?.shortName, teamName);
      if (!isOurs) continue;
      if (b.card === 'YELLOW_CARD') {
        const pn = b.player?.name || 'Desconocido';
        yellows[pn] = (yellows[pn] || 0) + 1;
      }
    }
  }
  return {
    suspendidos: Object.entries(yellows).filter(([,c]) => c >= 2).map(([n]) => n),
    enRiesgo: Object.entries(yellows).filter(([,c]) => c === 1).map(([n]) => n)
  };
}

// ===== NORMALIZAR =====
function normalizeData(data) {
  if (data.rounds && data.rounds.length > 0) return data;
  if (!data.matches) return { rounds: [] };
  const roundMap = {};
  for (const m of data.matches) {
    const rName = m.round || 'Unknown';
    if (!roundMap[rName]) roundMap[rName] = { name: rName, matches: [] };
    roundMap[rName].matches.push({ ...m, team1: typeof m.team1 === 'string' ? { name: m.team1 } : (m.team1 || {}), team2: typeof m.team2 === 'string' ? { name: m.team2 } : (m.team2 || {}) });
  }
  return { name: data.name, rounds: Object.values(roundMap) };
}

const data2026 = normalizeData(raw2026);
const data2022 = normalizeData(raw2022);
const data2018 = normalizeData(raw2018);
const r2026 = data2026.rounds || [];
const r2022 = data2022.rounds || [];
const r2018 = data2018.rounds || [];

const eloRatings = calcElo(r2018, r2022, r2026);

// ===== JUGADORES =====
function extractPlayers(data, year) {
  const players = {};
  for (const match of (data.matches || [])) {
    if (!match.score?.ft) continue;
    const t1 = typeof match.team1 === 'string' ? match.team1 : match.team1?.name;
    const t2 = typeof match.team2 === 'string' ? match.team2 : match.team2?.name;
    const proc = (goals, team) => {
      const mc = {};
      for (const g of (goals || [])) {
        if (g.owngoal) continue;
        const n = g.name;
        if (!players[n]) players[n] = { team, goals: 0, penalties: 0, hatTricks: 0, years: [] };
        players[n].goals++; players[n].team = team;
        if (g.penalty) players[n].penalties++;
        if (!players[n].years.includes(year)) players[n].years.push(year);
        mc[n] = (mc[n] || 0) + 1;
      }
      for (const [n, cnt] of Object.entries(mc)) { if (players[n] && cnt >= 3) players[n].hatTricks++; }
    };
    proc(match.goals1, t1); proc(match.goals2, t2);
  }
  return players;
}

function mergePlayers(...sources) {
  const merged = {};
  for (const [year, src] of sources) {
    const w = year === 2026 ? 3 : year === 2022 ? 2 : 1;
    for (const [name, s] of Object.entries(src)) {
      if (!merged[name]) merged[name] = { team: s.team, goals: 0, penalties: 0, hatTricks: 0, score: 0, years: [] };
      merged[name].goals += s.goals; merged[name].penalties += s.penalties; merged[name].hatTricks += s.hatTricks;
      merged[name].score += (s.goals * w) + (s.hatTricks * 5 * w) + (s.penalties * 0.5 * w);
      if (!merged[name].years.includes(year)) merged[name].years.push(year);
    }
  }
  return merged;
}

const allPlayers = mergePlayers(
  [2026, extractPlayers(raw2026, 2026)],
  [2022, extractPlayers(raw2022, 2022)],
  [2018, extractPlayers(raw2018, 2018)]
);

function getTopScorers(team, topN=5) {
  return Object.entries(allPlayers)
    .filter(([_, s]) => s.team === team)
    .sort((a, b) => b[1].score - a[1].score)
    .slice(0, topN)
    .map(([name, s]) => ({ nombre: name, goles: s.goals, penaltis: s.penalties, hatTricks: s.hatTricks, score: +s.score.toFixed(1), years: s.years }));
}

function teamQualityScore(team) {
  const scorers = getTopScorers(team, 3);
  return { score: +scorers.reduce((a, p) => a + p.score, 0).toFixed(1), topScorers: scorers };
}

// ===== ESTADISTICAS HISTORICAS =====
function calcStats(rounds, teamName) {
  let played=0, wins=0, draws=0, losses=0, gf=0, ga=0;
  for (const round of (rounds||[])) {
    for (const m of (round.matches||[])) {
      if (!m.score?.ft) continue;
      const t1=m.team1?.name, t2=m.team2?.name;
      if (t1!==teamName && t2!==teamName) continue;
      played++;
      const [gh, gay] = m.score.ft;
      if (t1===teamName) { gf+=gh; ga+=gay; if(gh>gay)wins++; else if(gh===gay)draws++; else losses++; }
      else { gf+=gay; ga+=gh; if(gay>gh)wins++; else if(gh===gay)draws++; else losses++; }
    }
  }
  return { played, wins, draws, losses, gf, ga, avgGF: played>0?(gf/played).toFixed(2):'0.00', avgGA: played>0?(ga/played).toFixed(2):'0.00' };
}

function getH2H(rounds, t1n, t2n) {
  const res=[];
  for (const round of (rounds||[])) {
    for (const m of (round.matches||[])) {
      if (!m.score?.ft) continue;
      const a=m.team1?.name, b=m.team2?.name;
      if ((a===t1n&&b===t2n)||(a===t2n&&b===t1n))
        res.push({ date:m.date, round:round.name, home:a, away:b, score:m.score.ft });
    }
  }
  return res;
}

function countBTTS(rounds, teamName) {
  let btts=0, total=0;
  for (const round of (rounds||[])) {
    for (const m of (round.matches||[])) {
      if (!m.score?.ft) continue;
      const t1=m.team1?.name, t2=m.team2?.name;
      if (t1!==teamName&&t2!==teamName) continue;
      total++;
      if (m.score.ft[0]>0&&m.score.ft[1]>0) btts++;
    }
  }
  return { btts, total, pct: total>0?((btts/total)*100).toFixed(0)+'%':'N/A' };
}

// ===== PARTIDOS PROXIMOS =====
const today = new Date(); today.setHours(0,0,0,0);
const in7Days = new Date(today); in7Days.setDate(today.getDate()+7);

let upcoming = [];
for (const round of r2026) {
  for (const m of (round.matches||[])) {
    if (!m.date) continue;
    const d = new Date(m.date);
    if (d>=today && d<=in7Days && !m.score?.ft) upcoming.push({...m, roundName: round.name});
  }
}
if (upcoming.length === 0) {
  for (const round of r2026) {
    for (const m of (round.matches||[])) {
      const noScore = !m.score?.ft;
      const hasTeams = m.team1?.name && !m.team1.name.match(/^[0-9WL]/);
      if (noScore && hasTeams) upcoming.push({...m, roundName: round.name});
    }
  }
  upcoming = upcoming.slice(0, 6);
}
if (upcoming.length === 0) {
  return [{ json: { _debug:true, partido:'DIAGNOSTICO', r2026:r2026.length, r2022:r2022.length, r2018:r2018.length, fdMatches:(rawFDMatches.matches||[]).length, fdGroups:(rawFDStandings.standings||[]).length } }];
}

return upcoming.map(match => {
  const t1 = match.team1?.name || 'TBD';
  const t2 = match.team2?.name || 'TBD';

  const stats1 = { wc2022: calcStats(r2022,t1), wc2018: calcStats(r2018,t1), btts: { wc2022: countBTTS(r2022,t1), wc2018: countBTTS(r2018,t1) } };
  const stats2 = { wc2022: calcStats(r2022,t2), wc2018: calcStats(r2018,t2), btts: { wc2022: countBTTS(r2022,t2), wc2018: countBTTS(r2018,t2) } };
  const forma1 = { ultimos5: getTeamForm(t1), standing: getTeamStanding(t1) };
  const forma2 = { ultimos5: getTeamForm(t2), standing: getTeamStanding(t2) };

  const elo1 = eloRatings[t1] || 1500;
  const elo2 = eloRatings[t2] || 1500;
  const eloDiff = elo1 - elo2;
  const eloWin1 = +(1 / (1 + Math.pow(10, -eloDiff / 400)) * 100).toFixed(1);

  const xg1 = estimateXG(forma1.ultimos5, stats1);
  const xg2 = estimateXG(forma2.ultimos5, stats2);

  const hf1 = getHomeFactor(t1);
  const hf2 = getHomeFactor(t2);

  const susp1 = getSuspensionRisk(t1);
  const susp2 = getSuspensionRisk(t2);

  return { json: {
    partido: `${t1} vs ${t2}`, fecha: match.date||'TBD', hora: match.time||'TBD',
    ronda: match.roundName||'TBD', grupo: match.group||'', estadio: match.ground||'',
    equipo1: t1, equipo2: t2,
    estadisticas: {
      [t1]: stats1,
      [t2]: stats2
    },
    h2h: { wc2022: getH2H(r2022,t1,t2), wc2018: getH2H(r2018,t1,t2), total: getH2H(r2022,t1,t2).length + getH2H(r2018,t1,t2).length },
    jugadores: {
      [t1]: { topScorers2026: getTopScorers(t1).filter(p=>p.years.includes(2026)), calidadEquipo: teamQualityScore(t1) },
      [t2]: { topScorers2026: getTopScorers(t2).filter(p=>p.years.includes(2026)), calidadEquipo: teamQualityScore(t2) }
    },
    formaActual: { [t1]: forma1, [t2]: forma2 },
    elo: {
      [t1]: { rating: elo1, winProb: eloWin1 },
      [t2]: { rating: elo2, winProb: +(100 - eloWin1).toFixed(1) },
      diferencia: Math.abs(eloDiff),
      favorito: eloDiff > 20 ? t1 : eloDiff < -20 ? t2 : 'Equilibrado'
    },
    xg: { [t1]: xg1, [t2]: xg2, total: +(xg1+xg2).toFixed(2) },
    localVisitante: { [t1]: hf1, [t2]: hf2 },
    bajas: {
      [t1]: { suspendidos: susp1.suspendidos, enRiesgo: susp1.enRiesgo },
      [t2]: { suspendidos: susp2.suspendidos, enRiesgo: susp2.enRiesgo }
    }
  }};
});

