const raw = $input.first()?.json || {};
let data = raw.data ?? raw;
if (typeof data === 'string') { try { data = JSON.parse(data); } catch(e) { data = {}; } }
if (typeof data !== 'object' || data === null || Array.isArray(data)) { data = {}; }
return [{ json: data }];

const item = $input.first()?.json || {};
if (item._debug) return [{ json: item }];

const t1 = item.equipo1;
const t2 = item.equipo2;
const e1 = item.estadisticas?.[t1] || {};
const e2 = item.estadisticas?.[t2] || {};
const h2h = item.h2h || {};
const jug = item.jugadores || {};
const forma = item.formaActual || {};
const elo = item.elo || {};
const xg = item.xg || {};
const lv = item.localVisitante || {};
const bajas = item.bajas || {};

function fmtStats(label, s22, s18) {
  let lines = `[${label}]\n`;
  lines += s22?.played > 0 ? `WC2022: ${s22.played}J ${s22.wins}V${s22.draws}E${s22.losses}D GF:${s22.gf} GC:${s22.ga} avg:${s22.avgGF}\n` : `WC2022: sin datos\n`;
  lines += s18?.played > 0 ? `WC2018: ${s18.played}J ${s18.wins}V${s18.draws}E${s18.losses}D GF:${s18.gf} GC:${s18.ga} avg:${s18.avgGF}\n` : `WC2018: sin datos\n`;
  return lines;
}

function fmtH2H(list, year) {
  return list?.length ? list.map(m => `  ${year} ${m.date}: ${m.home} ${m.score[0]}-${m.score[1]} ${m.away}`).join('\n') : '';
}

function fmtJugadores(jugData) {
  if (!jugData) return '';
  let lines = '';
  const sc26 = jugData.topScorers2026 || [];
  if (sc26.length) lines += `  Goleadores 2026: ${sc26.map(p => `${p.nombre}(${p.goles}G${p.hatTricks>0?' '+p.hatTricks+'HT':''}${p.penaltis>0?' '+p.penaltis+'PEN':''})`).join(', ')}\n`;
  const q = jugData.calidadEquipo;
  if (q?.score > 0) lines += `  Indice calidad: ${q.score}pts → ${(q.topScorers||[]).map(p=>`${p.nombre}:${p.score}`).join(', ')}\n`;
  return lines;
}

function fmtForma(teamName, fd) {
  if (!fd) return `  Sin datos\n`;
  let lines = '';
  const st = fd.standing;
  if (st) lines += `  ${st.grupo} pos.${st.posicion}: ${st.puntos}pts (${st.victorias}V${st.empates}E${st.derrotas}D | GF:${st.gf} GC:${st.gc})\n`;
  const ult = fd.ultimos5 || [];
  if (ult.length) {
    lines += `  Ultimos ${ult.length} WC2026: ${ult.map(m=>`${m.resultado}(${m.marcador} vs ${m.rival})`).join(' | ')}\n`;
    const wins = ult.filter(m=>m.resultado==='V').length;
    const bttsCnt = ult.filter(m=>{ const [a,b]=m.marcador.split('-').map(Number); return a>0&&b>0; }).length;
    lines += `  Racha: ${wins}V ${ult.filter(m=>m.resultado==='E').length}E ${ult.length-wins-ult.filter(m=>m.resultado==='E').length}D | BTTS: ${bttsCnt}/${ult.length}\n`;
  } else {
    lines += `  Sin partidos completados en WC2026 aun\n`;
  }
  return lines;
}

const h2hTexto = [fmtH2H(h2h.wc2022,'WC2022'), fmtH2H(h2h.wc2018,'WC2018')].filter(Boolean).join('\n');

const eloT1 = elo[t1] || {};
const eloT2 = elo[t2] || {};
const lvT1 = lv[t1] || { label: 'Visitante', boost: 0 };
const lvT2 = lv[t2] || { label: 'Visitante', boost: 0 };
const bajasT1 = bajas[t1] || { suspendidos: [], enRiesgo: [] };
const bajasT2 = bajas[t2] || { suspendidos: [], enRiesgo: [] };

const resumen = [
  '=== ANALISIS PARTIDO MUNDIAL 2026 (MODELO 24H) ===',
  `Partido: ${item.partido}`,
  `Fecha: ${item.fecha} ${item.hora||''}`,
  `Ronda: ${item.ronda} ${item.grupo?'| Grupo: '+item.grupo:''}`,
  `Estadio: ${item.estadio||'Por definir'}`,
  '',
  '--- ELO Y PROBABILIDADES ---',
  `${t1}: ELO ${eloT1.rating||1500} | Prob. victoria: ${eloT1.winProb||'?'}%`,
  `${t2}: ELO ${eloT2.rating||1500} | Prob. victoria: ${eloT2.winProb||'?'}%`,
  `Diferencia ELO: ${elo.diferencia||0} pts | Favorito por ELO: ${elo.favorito||'Equilibrado'}`,
  '',
  '--- xG ESTIMADO ---',
  `${t1}: xG ${xg[t1]||'?'} goles/partido`,
  `${t2}: xG ${xg[t2]||'?'} goles/partido`,
  `Total xG: ${xg.total||'?'} (referencia Over/Under 2.5)`,
  '',
  '--- LOCAL/VISITANTE ---',
  `${t1}: ${lvT1.label}${lvT1.boost > 0 ? ` (+${Math.round(lvT1.boost*100)}% ventaja estimada)` : ''}`,
  `${t2}: ${lvT2.label}${lvT2.boost > 0 ? ` (+${Math.round(lvT2.boost*100)}% ventaja estimada)` : ''}`,
  '',
  '--- BAJAS Y SUSPENSIONES (tarjetas WC2026) ---',
  `${t1}: Suspendidos: ${bajasT1.suspendidos.length ? bajasT1.suspendidos.join(', ') : 'Ninguno'} | En riesgo (1 amarilla): ${bajasT1.enRiesgo.length ? bajasT1.enRiesgo.join(', ') : 'Ninguno'}`,
  `${t2}: Suspendidos: ${bajasT2.suspendidos.length ? bajasT2.suspendidos.join(', ') : 'Ninguno'} | En riesgo (1 amarilla): ${bajasT2.enRiesgo.length ? bajasT2.enRiesgo.join(', ') : 'Ninguno'}`,
  `NOTA: Lesiones y once titular se analizan en el Modelo de Ajuste (30-60 min antes).`,
  '',
  '--- FORMA ACTUAL WC 2026 ---',
  `${t1}:`,
  fmtForma(t1, forma[t1]),
  `${t2}:`,
  fmtForma(t2, forma[t2]),
  '--- ESTADISTICAS HISTORICAS (WC 2018 + 2022) ---',
  fmtStats(t1, e1.wc2022, e1.wc2018),
  fmtStats(t2, e2.wc2022, e2.wc2018),
  `BTTS historico:`,
  `  ${t1}: WC2022 ${e1.btts?.wc2022?.pct||'N/A'} (${e1.btts?.wc2022?.btts||0}/${e1.btts?.wc2022?.total||0}), WC2018 ${e1.btts?.wc2018?.pct||'N/A'} (${e1.btts?.wc2018?.btts||0}/${e1.btts?.wc2018?.total||0})`,
  `  ${t2}: WC2022 ${e2.btts?.wc2022?.pct||'N/A'} (${e2.btts?.wc2022?.btts||0}/${e2.btts?.wc2022?.total||0}), WC2018 ${e2.btts?.wc2018?.pct||'N/A'} (${e2.btts?.wc2018?.btts||0}/${e2.btts?.wc2018?.total||0})`,
  '',
  '--- H2H MUNDIALES ---',
  h2h.total > 0 ? h2hTexto : 'Sin H2H en WC 2018/2022',
  '',
  '--- CALIDAD DE JUGADORES ---',
  `${t1}:`,
  fmtJugadores(jug[t1]),
  `${t2}:`,
  fmtJugadores(jug[t2])
].join('\n').trim();

return [{ json: { ...item, _resumen: resumen } }];
